function prt = fGetPartStrV03(str,left,right)% gives a part of string specified by character left and right.%% prt = fGetPartStrV03(str,left,right)% % prt: part of a string% str: input string% left: character% right: character%% *********************************% Get Part of String, ver.3% Kei Nakamura% Created on Monday, May 14th 2007.% Modified on Sunday, August 13th 2007.%% ver.2: in case of no finding% Ver.3: from left, cut, then right%%% mainleftD = double(left);           % left in doublerightD = double(right);         % right in doublestrD = double(str);             % str in doubleleftI = find(strD==leftD);      % left Indexif leftI>=0;    leftI = leftI+1;else    leftI = 1;endstr = str(leftI:end);strD = strD(leftI:end);rightI = find(strD==rightD);    % right Indexif rightI>=0    rightI = rightI - 1;else    rightI = max(size(str));endprt = str(1:rightI);    % part of index
